const inputData = $input.all();
const jobs = [];

for (const item of inputData) {
  const jobList = item.json?.zpData?.jobList || [];
  for (const job of jobList) {
    jobs.push({
      json: {
        jobId: job.encryptJobId || job.jobId || '',
        company: job.brandName || job.companyName || 'Unknown',
        role: job.jobName || '',
        location: (job.areaDistrict || '') + ' ' + (job.businessDistrict || ''),
        salary: job.salaryDesc || '',
        experience: job.jobExperience || '',
        education: job.jobDegree || '',
        skills: (job.skills || []).join(', '),
        jd: [
          job.jobName || '',
          '公司: ' + (job.brandName || ''),
          '经验: ' + (job.jobExperience || ''),
          '学历: ' + (job.jobDegree || ''),
          '技能: ' + (job.skills || []).join(', '),
          '薪资: ' + (job.salaryDesc || '')
        ].join('\n'),
        url: 'https://www.zhipin.com/job_detail/' + (job.encryptJobId || '') + '.html',
        bossTitle: job.bossTitle || '',
        bossOnline: job.bossOnline || false,
        source: 'boss'
      }
    });
  }
}

if (jobs.length === 0) {
  return [{ json: { _empty: true, message: 'No jobs found' } }];
}

return jobs;

const job = $input.all()[0].json;
if (job._empty) {
  return [{ json: { _skip: true } }];
}
return [{ json: job }];

const scored = $input.all()[0].json;
const original = $('解析岗位数据').first().json;

return [{
  json: {
    ...original,
    score: scored.score || 0,
    score_raw: scored.score_raw || 'N/A',
    archetype: scored.archetype || '',
    legitimacy: scored.legitimacy || '',
    report: (scored.report || '').substring(0, 2000),
    scored_at: new Date().toISOString()
  }
}];

const job = $input.all()[0].json;
return [{
  json: {
    _action: 'save_high_score',
    jobId: job.jobId,
    company: job.company,
    role: job.role,
    location: job.location,
    salary: job.salary,
    score: job.score,
    status: 'notified',
    url: job.url
  }
}];

const job = $input.all()[0].json;
return [{
  json: {
    _action: 'save_low_score',
    jobId: job.jobId,
    company: job.company,
    role: job.role,
    score: job.score,
    status: 'skipped'
  }
}];
